window.QB_H8_2U3_L8.push(
  {c:'建国',q:'十一届三中全会的中心议题是什么？',o:['批判四人帮','讨论1977年的工作计划','把工作重点转移到社会主义现代化建设上来','讨论改革对外开放问题'],a:2,e:'十一届三中全会（1978年12月）的中心议题是：把全党工作重点转移到社会主义现代化建设上来，同时进行拨乱反正，并讨论了农业问题，为改革开放奠定了基础。'},
  {c:'建国',q:'十一届三中全会停止使用的口号是？',o:['实事求是','解放思想','以阶级斗争为纲','改革开放'],a:2,e:'十一届三中全会明确停止使用"以阶级斗争为纲"的口号，将工作重心从政治运动转向经济建设，把阶级斗争为纲的错误路线彻底纠正，是历史的伟大转折。'},
  {c:'建国',q:'"拨乱反正"完成的标志是？',o:['文革结束','十一届三中全会召开','1981年十一届六中全会通过《关于建国以来党的若干历史问题的决议》','邓小平南方谈话'],a:2,e:'1981年，中共十一届六中全会通过《关于建国以来党的若干历史问题的决议》，对毛泽东的历史评价和文革问题作出正确结论，标志着拨乱反正任务的基本完成。'},
  {c:'建国',q:'十一届三中全会确定的党的思想路线是？',o:['以阶级斗争为纲','以经济建设为中心','解放思想、实事求是','坚持两个凡是'],a:2,e:'十一届三中全会重新确立了"解放思想、实事求是"的思想路线，彻底否定了"两个凡是"的错误方针，恢复了毛泽东思想的正确本质，为改革开放提供了思想指引。'},
  {c:'建国',q:'"两个凡是"的错误本质是？',o:['过分重视实践','教条主义、不思变通，用过去的话解决今天的问题，阻碍思想解放','坚持了实事求是','强调改革创新'],a:1,e:'"两个凡是"（凡是毛主席的决策都坚决维护，凡是毛主席的指示都坚决遵守）的错误本质是：将个人指示凌驾于客观实际之上的教条主义，是不讲实事求是的僵化思想，严重阻碍了历史前进。'},
  {c:'建国',q:'十一届三中全会后，中国实行改革的顺序是？',o:['先城市后农村','先对外开放后对内改革','先农村后城市（先农村改革，后城市经济体制改革）','城乡同步改革'],a:2,e:'改革顺序：①1978年后先从农村（家庭联产承包责任制）开始突破②1984年起城市经济体制改革全面展开（以增强企业活力为中心）③对外开放从1980年经济特区开始推进，是先农村后城市的渐进式改革路线。'},
  {c:'建国',q:'"文化大革命"结束的时间是？',o:['1975年','1976年10月（四人帮被粉碎）','1978年','1977年'],a:1,e:'1976年10月6日，华国锋、叶剑英等领导人一举粉碎以江青为首的"四人帮"反革命集团，结束了长达十年（1966-1976年）的文化大革命，这是粉碎"四人帮"而不是毛泽东去世（同年9月）为标志。'}
);

