window.QB_H8_2U3_L10.push(
  {c:'建国',q:'下列对于"一国两制"的表述，正确的是？',o:['港澳台地区将来都实行社会主义','一国两制意味着中国分裂为两个国家','在统一的中华人民共和国内，大陆实行社会主义，港澳台保持原有资本主义制度不变','大陆也将实行资本主义'],a:2,e:'"一国两制"：在中华人民共和国统一框架下，大陆主体实行社会主义制度，香港、澳门、台湾等地区保持原有的资本主义制度，50年不变，高度自治（外交国防除外）。'},
  {c:'建国',q:'香港（1997年）和澳门（1999年）的回归，采用了什么方式？',o:['武力解放','外交谈判和平回归，实行"一国两制"','购回','联合国仲裁'],a:1,e:'香港和澳门分别于1997年7月1日和1999年12月20日回归祖国，采用了"一国两制"的和平方式：中英、中葡两国通过外交谈判，平稳移交主权，原有资本主义制度保持不变。'},
  {c:'建国',q:'1984年以后，对外开放从经济特区向沿海扩展的具体措施是？',o:['开放北京、上海等内陆城市','开放14个沿海城市，建立经济技术开发区','在全国同步开放','只限于广东和福建'],a:1,e:'1984年，国家决定进一步开放天津、上海、大连、青岛等14个沿海城市，同时建立经济技术开发区，引进外资、技术和管理经验，使对外开放从经济特区向沿海城市延伸。'},
  {c:'建国',q:'上海浦东开发区（1990年）设立的战略意义是？',o:['是沿海经济特区的延伸','以上海为龙头，带动长江流域乃至全国的经济发展，是改革开放向纵深推进的重要标志','只为上海本地经济服务','是专门为外资服务的区域'],a:1,e:'浦东开发区：①突破了改革开放因1989年政治风波的低谷②以上海为龙头带动长三角和长江流域发展③是90年代对外开放的重大战略举措④标志改革开放向更高层次、更广领域推进。'},
  {c:'建国',q:'中国对外开放的格局特点是？',o:['重点在西部内陆','全面均衡，城乡一体','全方位、多层次、宽领域的对外开放格局','以东南亚为主要对象'],a:2,e:'中国对外开放格局：全方位（面向世界各国各地区）、多层次（从经济特区到沿海城市到内地，层次递进）、宽领域（从经济到科技、文化、教育等各领域），是改革开放的重要成果。'},
  {c:'建国',q:'2001年，中国加入世界贸易组织（WTO）的意义是？',o:['无意义','标志中国全面融入全球经济体系，对外开放进入新阶段，推动经济持续快速发展','使中国经济变成资本主义经济','增加了中国对外国的依赖性'],a:1,e:'2001年中国加入WTO的意义：①标志中国全面融入全球经济体系②对外开放进入新阶段③推动了对外贸易高速增长④中国此后GDP超越德、日，成为全球第二大经济体，是改革开放的重大里程碑。'}
);

